using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// HUD principal do jogo (Tarefa #32) — elementos sempre visíveis (ou
/// temporariamente visíveis) durante o jogo, fora dos menus:
///
/// - Corações (vida actual/máxima — <see cref="PlayerProgress.HealthChanged"/>).
/// - Item equipado + quantidade (<see cref="PlayerProgress.EquippedItemChanged"/>,
///   <see cref="GameDatabase.FindItem"/>, <see cref="PlayerProgress.GetItemQuantity(ItemData)"/>).
/// - Forma actual (<see cref="FormSwitcher.OnFormApplied"/>) + cooldown de
///   transformação (<see cref="FormSwitcher.TransformCooldownRemaining01"/>).
/// - Cooldown/estado/disponibilidade da habilidade da forma actual (Tarefa
///   #34 — <see cref="AbilityRouter.GetPrimaryAbilityCooldownSource"/> devolve
///   um <see cref="IActiveAbility"/> para TODAS as formas). Se
///   <see cref="IActiveAbility.CooldownDuration"/> for 0 (habilidades
///   passivas ou sem cooldown próprio), nenhum indicador de cooldown é
///   mostrado; caso contrário mostra-se o tempo restante e o ícone fica
///   acinzentado (<see cref="abilityCooldownColor"/>) durante o cooldown, ou
///   realçado (<see cref="abilityActiveColor"/>) enquanto
///   <see cref="IAbility.IsActive"/> for true.
/// - Sementes (<see cref="PlayerProgress.SeedsChanged"/>) e Runas de Gaia
///   (<see cref="PlayerProgress.RunasChanged"/>).
/// - Banner com o nome da área actual
///   (<see cref="WorldState.CurrentAreaChanged"/>), com fade in/out e
///   ocultação automática.
/// - Mensagem de save (<see cref="SaveManager.OnSaveCompleted"/>), com
///   ocultação automática.
/// - População da vila (<see cref="WorldState.GetVillagePopulation"/>),
///   mostrada apenas quando <see cref="AreaData.isCity"/> é true. O villageId
///   vem de <see cref="AreaData.world"/> → <see cref="WorldData.mainVillageId"/>
///   (uma vila principal por mundo) — chamar <see cref="RefreshVillagePopulation()"/>
///   depois de <see cref="WorldState.SetVillagePopulation"/> alterar a
///   população, para o HUD actualizar sem esperar por uma mudança de área.
///
/// NÃO incluído aqui (UI próprio, separado):
/// - Prompt de interacção: <see cref="InteractionPromptUI"/>.
/// - Barra de vida de boss: <see cref="BossHealthBarUI"/>.
/// - HUD de Desafio (nome, cronómetro, lista de objectivos com progresso):
///   <see cref="ChallengeHudUI"/> (Sistema de Desafios, Tarefa #12) — substitui
///   o scaffolding antigo "ChallengeObjectiveUI" da Tarefa #32, removido por
///   ficar redundante (Tarefa #18).
/// - Feedback de "animal bloqueado na roda": já tratado por
///   FormWheelNodeUI/FormWheelUI (Tarefa #21).
///
/// Montagem no Editor: ligar "formSwitcher"/"abilityRouter" ao GameObject do
/// Player (ou deixar vazio para auto-detectar via tag "Player" em Start), e
/// todas as referências de UI abaixo dentro do Canvas do HUD.
/// </summary>
public class HUDController : MonoBehaviour
{
    [Header("Player (auto-detectado via tag 'Player' se vazio)")]
    [SerializeField] private FormSwitcher formSwitcher;
    [SerializeField] private AbilityRouter abilityRouter;

    [Header("Corações")]
    [SerializeField] private Transform heartsContainer;
    [SerializeField] private Image heartIconPrefab;
    [SerializeField] private Sprite heartFullSprite;
    [SerializeField] private Sprite heartEmptySprite;

    [Header("Item Equipado")]
    [SerializeField] private Image equippedItemIcon;
    [SerializeField] private TMP_Text equippedItemQuantityText;

    [Header("Forma Actual")]
    [SerializeField] private Image formIconImage;
    [Tooltip("Image do tipo 'Filled' (radial) sobreposta ao ícone da forma — fillAmount = TransformCooldownRemaining01 (1 = acabou de transformar, 0 = pronto).")]
    [SerializeField] private Image transformCooldownFill;

    [Header("Cooldown de Habilidade")]
    [Tooltip("Ícone do botão de Habilidade (Tarefa #34) — acinzentado (abilityCooldownColor) durante o cooldown, realçado (abilityActiveColor) enquanto a habilidade está activa (IAbility.IsActive), branco normal nos restantes casos. Formas cuja habilidade primária não tem cooldown próprio (IActiveAbility.CooldownDuration == 0) nunca mostram o texto/indicador de cooldown.")]
    [SerializeField] private Image abilityIconImage;
    [SerializeField] private TMP_Text abilityCooldownText;
    [SerializeField] private Color abilityCooldownColor = new Color(1f, 1f, 1f, 0.4f);
    [Tooltip("Cor do ícone de habilidade enquanto a habilidade está activa (ex: ShellGuard em guarda, Camo activo, Glide a planar).")]
    [SerializeField] private Color abilityActiveColor = new Color(0.6f, 1f, 0.6f, 1f);

    [Header("Recursos")]
    [Tooltip("GameObject raiz do display de Sementes — ocultado automaticamente e mostrado apenas temporariamente ao apanhar/comprar sementes (Tarefa #37).")]
    [SerializeField] private GameObject sementesRoot;
    [SerializeField] private CanvasGroup sementesCanvasGroup;
    [SerializeField] private TMP_Text sementesText;
    [Tooltip("Duração (segundos) em que o display de Sementes fica visível após uma mudança (Tarefa #37).")]
    [SerializeField] private float sementesDuration = 3f;
    [Tooltip("Duração do fade in/out do display de Sementes (Tarefa #37).")]
    [SerializeField] private float sementesFadeDuration = 0.3f;
    [SerializeField] private TMP_Text runasText;

    [Header("Banner de Área")]
    [SerializeField] private GameObject areaBannerRoot;
    [SerializeField] private CanvasGroup areaBannerCanvasGroup;
    [SerializeField] private TMP_Text areaNameText;
    [SerializeField] private float areaBannerDuration = 3f;
    [SerializeField] private float areaBannerFadeDuration = 0.4f;

    [Header("Mensagem de Save")]
    [SerializeField] private GameObject saveIndicatorRoot;
    [SerializeField] private TMP_Text saveIndicatorText;
    [SerializeField] private string saveMessage = "Jogo guardado";
    [SerializeField] private float saveIndicatorDuration = 2f;

    [Header("População da Vila")]
    [SerializeField] private GameObject villagePopulationRoot;
    [SerializeField] private TMP_Text villagePopulationText;
    [SerializeField] private string villagePopulationFormat = "{0} / {1}";

    private readonly List<Image> _heartIcons = new List<Image>();
    private Coroutine _areaBannerRoutine;
    private Coroutine _saveIndicatorRoutine;
    private Coroutine _sementesRoutine;

    // ==================== Ciclo de Vida ====================

    private void OnEnable()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null)
        {
            progress.HealthChanged += OnHealthChanged;
            progress.SeedsChanged += OnSeedsChanged;
            progress.RunasChanged += OnRunasChanged;
            progress.EquippedItemChanged += OnEquippedItemChanged;
            progress.PickupCollected += OnPickupCollected;
        }

        var world = WorldState.Instance;
        if (world != null) world.CurrentAreaChanged += OnCurrentAreaChanged;

        WorldState.VillagePopulationChanged += OnVillagePopulationChanged;

        var saveManager = SaveManager.Instance;
        if (saveManager != null) saveManager.OnSaveCompleted += OnSaveCompleted;
    }

    private void OnDisable()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null)
        {
            progress.HealthChanged -= OnHealthChanged;
            progress.SeedsChanged -= OnSeedsChanged;
            progress.RunasChanged -= OnRunasChanged;
            progress.EquippedItemChanged -= OnEquippedItemChanged;
            progress.PickupCollected -= OnPickupCollected;
        }

        var world = WorldState.Instance;
        if (world != null) world.CurrentAreaChanged -= OnCurrentAreaChanged;

        WorldState.VillagePopulationChanged -= OnVillagePopulationChanged;

        var saveManager = SaveManager.Instance;
        if (saveManager != null) saveManager.OnSaveCompleted -= OnSaveCompleted;

        if (formSwitcher != null) formSwitcher.OnFormApplied -= OnFormApplied;
    }

    private void Start()
    {
        if (formSwitcher == null || abilityRouter == null)
        {
            var player = GameObject.FindGameObjectWithTag("Player");
            if (player != null)
            {
                if (formSwitcher == null) formSwitcher = player.GetComponent<FormSwitcher>();
                if (abilityRouter == null) abilityRouter = player.GetComponent<AbilityRouter>();
            }
        }

        if (formSwitcher != null)
        {
            formSwitcher.OnFormApplied += OnFormApplied;
            OnFormApplied(formSwitcher.CurrentForm);
        }

        var progress = PlayerProgress.Instance;
        if (progress != null)
        {
            RefreshHearts(progress.currentHearts, progress.maxHearts);
            OnSeedsChanged(progress.sementes);
            OnRunasChanged(progress.runasDeGaia, progress.totalRunasDeGaiaCollected);
            RefreshEquippedItem(progress.equippedItemId);
        }

        RefreshVillagePopulation(WorldState.Instance != null ? WorldState.Instance.CurrentArea : null);

        if (areaBannerRoot != null) areaBannerRoot.SetActive(false);
        if (saveIndicatorRoot != null) saveIndicatorRoot.SetActive(false);
        if (sementesRoot != null) sementesRoot.SetActive(false);
        SetAbilityIndicator(false, false, false);
    }

    private void Update()
    {
        UpdateTransformCooldown();
        UpdateAbilityCooldown();
    }

    // ==================== Corações ====================

    private void OnHealthChanged(int current, int max) => RefreshHearts(current, max);

    private void RefreshHearts(int current, int max)
    {
        if (_heartIcons.Count != max) RebuildHearts(max);

        for (int i = 0; i < _heartIcons.Count; i++)
        {
            if (_heartIcons[i] == null) continue;
            _heartIcons[i].sprite = i < current ? heartFullSprite : heartEmptySprite;
        }
    }

    private void RebuildHearts(int max)
    {
        foreach (var icon in _heartIcons)
            if (icon != null) Destroy(icon.gameObject);

        _heartIcons.Clear();

        if (heartIconPrefab == null || heartsContainer == null) return;

        for (int i = 0; i < max; i++)
        {
            var icon = Instantiate(heartIconPrefab, heartsContainer);
            icon.gameObject.SetActive(true);
            _heartIcons.Add(icon);
        }
    }

    // ==================== Item Equipado ====================

    private void OnEquippedItemChanged(string itemId) => RefreshEquippedItem(itemId);

    private void OnPickupCollected(PickupType type, string pickupId)
    {
        // A quantidade recolhida pode ser do item actualmente equipado —
        // actualiza o número mostrado no HUD.
        var progress = PlayerProgress.Instance;
        RefreshEquippedItem(progress != null ? progress.equippedItemId : null);
    }

    private void RefreshEquippedItem(string itemId)
    {
        ItemData item = null;
        if (!string.IsNullOrEmpty(itemId) && GameDatabase.Instance != null)
            item = GameDatabase.Instance.FindItem(itemId);

        if (equippedItemIcon != null)
        {
            equippedItemIcon.sprite = item != null ? item.icon : null;
            equippedItemIcon.enabled = item != null && item.icon != null;
        }

        if (equippedItemQuantityText != null)
        {
            if (item != null && PlayerProgress.Instance != null)
            {
                int quantity = PlayerProgress.Instance.GetItemQuantity(item);
                equippedItemQuantityText.text = $"x{quantity}";
                equippedItemQuantityText.gameObject.SetActive(true);
            }
            else
            {
                equippedItemQuantityText.gameObject.SetActive(false);
            }
        }
    }

    // ==================== Forma Actual / Cooldown de Transformação ====================

    private void OnFormApplied(AnimalFormData form)
    {
        if (formIconImage == null) return;

        formIconImage.sprite = form != null ? form.icon : null;
        formIconImage.enabled = form != null && form.icon != null;
    }

    private void UpdateTransformCooldown()
    {
        if (transformCooldownFill == null || formSwitcher == null) return;

        transformCooldownFill.fillAmount = formSwitcher.TransformCooldownRemaining01;
    }

    // ==================== Cooldown de Habilidade ====================

    private void UpdateAbilityCooldown()
    {
        if (abilityRouter == null)
        {
            SetAbilityIndicator(false, false, false);
            return;
        }

        var ability = abilityRouter.GetPrimaryAbilityCooldownSource();

        // Sem fonte, ou habilidade sem cooldown próprio (passiva/instantânea
        // sem cooldown) — Tarefa #34: não mostrar indicador de cooldown.
        if (ability == null || ability.CooldownDuration <= 0f)
        {
            SetAbilityIndicator(false, false, ability != null && ability.IsActive);
            return;
        }

        float remaining = Mathf.Max(0f, ability.CooldownRemaining);
        bool onCooldown = remaining > 0f;

        SetAbilityIndicator(true, onCooldown, ability.IsActive);
        if (abilityCooldownText != null) abilityCooldownText.text = remaining.ToString("F1");
    }

    /// <summary>
    /// Actualiza o ícone/texto do botão de Habilidade (Tarefa #34):
    /// - showCooldownText: true se esta habilidade tem cooldown próprio
    ///   (IActiveAbility.CooldownDuration > 0) e o HUD deve mostrar o texto de
    ///   tempo restante.
    /// - onCooldown: true enquanto o cooldown estiver a decorrer (ícone
    ///   acinzentado, texto visível).
    /// - isActive: true enquanto a habilidade estiver num estado activo
    ///   (IAbility.IsActive) — ícone realçado com abilityActiveColor, desde
    ///   que não esteja em cooldown.
    /// </summary>
    private void SetAbilityIndicator(bool showCooldownText, bool onCooldown, bool isActive)
    {
        if (abilityCooldownText != null) abilityCooldownText.gameObject.SetActive(showCooldownText && onCooldown);

        if (abilityIconImage != null)
        {
            if (onCooldown) abilityIconImage.color = abilityCooldownColor;
            else if (isActive) abilityIconImage.color = abilityActiveColor;
            else abilityIconImage.color = Color.white;
        }
    }

    // ==================== Recursos ====================

    private void OnSeedsChanged(int sementes)
    {
        if (sementesText != null) sementesText.text = sementes.ToString();

        // Tarefa #37: mostrar temporariamente e depois esconder.
        if (sementesRoot != null)
        {
            if (_sementesRoutine != null) StopCoroutine(_sementesRoutine);
            _sementesRoutine = StartCoroutine(SementesBannerRoutine());
        }
    }

    private IEnumerator SementesBannerRoutine()
    {
        if (sementesRoot != null) sementesRoot.SetActive(true);

        yield return FadeCanvasGroup(sementesCanvasGroup, 0f, 1f, sementesFadeDuration);
        yield return new WaitForSeconds(sementesDuration);
        yield return FadeCanvasGroup(sementesCanvasGroup, 1f, 0f, sementesFadeDuration);

        if (sementesRoot != null) sementesRoot.SetActive(false);
        _sementesRoutine = null;
    }

    private void OnRunasChanged(int runas, int totalCollected)
    {
        if (runasText != null) runasText.text = runas.ToString();
    }

    // ==================== Banner de Área ====================

    private void OnCurrentAreaChanged(AreaData area)
    {
        if (area != null && areaNameText != null)
        {
            areaNameText.text = area.displayName;

            if (_areaBannerRoutine != null) StopCoroutine(_areaBannerRoutine);
            _areaBannerRoutine = StartCoroutine(AreaBannerRoutine());
        }

        RefreshVillagePopulation(area);
    }

    private IEnumerator AreaBannerRoutine()
    {
        if (areaBannerRoot != null) areaBannerRoot.SetActive(true);

        yield return FadeCanvasGroup(areaBannerCanvasGroup, 0f, 1f, areaBannerFadeDuration);
        yield return new WaitForSeconds(areaBannerDuration);
        yield return FadeCanvasGroup(areaBannerCanvasGroup, 1f, 0f, areaBannerFadeDuration);

        if (areaBannerRoot != null) areaBannerRoot.SetActive(false);
        _areaBannerRoutine = null;
    }

    // ==================== Mensagem de Save ====================

    private void OnSaveCompleted(int slotIndex)
    {
        if (saveIndicatorRoot == null) return;

        if (saveIndicatorText != null) saveIndicatorText.text = saveMessage;

        if (_saveIndicatorRoutine != null) StopCoroutine(_saveIndicatorRoutine);
        _saveIndicatorRoutine = StartCoroutine(SaveIndicatorRoutine());
    }

    private IEnumerator SaveIndicatorRoutine()
    {
        saveIndicatorRoot.SetActive(true);
        yield return new WaitForSeconds(saveIndicatorDuration);
        saveIndicatorRoot.SetActive(false);
        _saveIndicatorRoutine = null;
    }

    // ==================== População da Vila ====================

    /// <summary>
    /// Reage a WorldState.VillagePopulationChanged — actualiza o HUD da população
    /// sempre que qualquer vila muda, sem esperar pela próxima mudança de área.
    /// </summary>
    private void OnVillagePopulationChanged(string changedVillageId, int current, int max)
    {
        // Actualiza apenas se o HUD estiver a mostrar esta vila.
        var area = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        if (area == null || !area.isCity) return;

        string currentVillageId = area.world != null ? area.world.mainVillageId : null;
        if (currentVillageId != changedVillageId) return;

        RefreshVillagePopulation(area);
    }

    private void RefreshVillagePopulation(AreaData area)
    {
        bool show = false;

        string villageId = area != null && area.world != null ? area.world.mainVillageId : null;

        if (area != null && area.isCity && !string.IsNullOrEmpty(villageId) && WorldState.Instance != null)
        {
            var pop = WorldState.Instance.GetVillagePopulation(villageId);
            if (pop != null)
            {
                show = true;
                if (villagePopulationText != null)
                    villagePopulationText.text = string.Format(villagePopulationFormat, pop.current, pop.max);
            }
        }

        if (villagePopulationRoot != null) villagePopulationRoot.SetActive(show);
    }

    /// <summary>
    /// Chamar depois de <see cref="WorldState.SetVillagePopulation"/> alterar
    /// a população da área actual, para o HUD actualizar imediatamente (sem
    /// esperar por uma mudança de área).
    /// </summary>
    public void RefreshVillagePopulation()
    {
        RefreshVillagePopulation(WorldState.Instance != null ? WorldState.Instance.CurrentArea : null);
    }

    // ==================== Utilidades ====================

    private static IEnumerator FadeCanvasGroup(CanvasGroup group, float from, float to, float duration)
    {
        if (group == null) yield break;

        if (duration <= 0f)
        {
            group.alpha = to;
            yield break;
        }

        float t = 0f;
        group.alpha = from;
        while (t < duration)
        {
            t += Time.deltaTime;
            group.alpha = Mathf.Lerp(from, to, t / duration);
            yield return null;
        }

        group.alpha = to;
    }
}
